import { type Rule, rules } from '#db-next'

import { store } from './store.ts'

const Base = () => {
  return store.exibeBase ? (
    <div>
      <br />
      <table style={{ width: '100%' }} className="table-grid">
        <caption>Exigências</caption>
        <thead>
          <tr>
            <th style={{ width: '10%' }}>Descrição</th>
            <th style={{ width: '20%' }}>Praga</th>
            <th style={{ width: '10%' }}>Partida</th>
            <th style={{ width: '10%' }}>Origem</th>
            <th style={{ width: '10%' }}>Destino</th>
            <th style={{ width: '15%' }}>Legislação</th>
            <th style={{ width: '30%' }}>Exigências</th>
          </tr>
        </thead>
        <tbody>
          {(rules as Rule[]).map((item, i: number) => {
            return (
              <tr key={i}>
                <td style={{ width: '10%' }}>
                  <span>{item.desc}</span>
                </td>
                <td style={{ width: '20%' }} className="italic">
                  <span className="italic">{item.prag}</span>
                </td>
                <td style={{ width: '10%' }}>
                  <span>{item.part.toString()}</span>
                </td>
                <td style={{ width: '10%' }}>
                  <span>{item.status_origem?.toString() || ''}</span>
                </td>
                <td style={{ width: '10%' }}>
                  <span>{item.status_destino?.toString() || ''}</span>
                </td>

                <td style={{ width: '15%' }}>
                  <span>{item.leg}</span>
                </td>
                <td style={{ width: '30%' }}>
                  <div style={{ margin: '6px' }}>
                    {(item.exig as string[]).map((exigen, ix) => {
                      return (
                        <p key={ix}>
                          {ix + 1} - {exigen}
                        </p>
                      )
                    })}
                  </div>
                </td>
              </tr>
            )
          })}
        </tbody>
        <tfoot className="form-barra-botoes">
          <tr>
            <td />
          </tr>
        </tfoot>
      </table>
    </div>
  ) : (
    <div />
  )
}

export default Base
